import{_ as a,o as r,c as e,ae as o}from"./chunks/framework.C8MNLDzb.js";const p=JSON.parse('{"title":"《史记·项羽本纪》节选","description":"","frontmatter":{},"headers":[],"relativePath":"shi/项羽本纪.md","filePath":"shi/项羽本纪.md"}'),d={name:"shi/项羽本纪.md"};function i(l,t,n,h,s,c){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="《史记·项羽本纪》节选" tabindex="-1">《史记·项羽本纪》节选 <a class="header-anchor" href="#《史记·项羽本纪》节选" aria-label="Permalink to &quot;《史记·项羽本纪》节选&quot;">​</a></h1><hr><h2 id="原文节选" tabindex="-1">原文节选 <a class="header-anchor" href="#原文节选" aria-label="Permalink to &quot;原文节选&quot;">​</a></h2><blockquote><p>项籍者，下相人也，字羽。初起时，年二十四。其季父项梁。梁父即楚将项燕，为秦将王翦所戮者也。项氏世世为楚将，封于项，故姓项氏。</p></blockquote><hr><h2 id="人物简介" tabindex="-1">人物简介 <a class="header-anchor" href="#人物简介" aria-label="Permalink to &quot;人物简介&quot;">​</a></h2><p><strong>项羽</strong>（公元前232年—公元前202年）</p><p>名籍，字羽，楚国下相（今江苏宿迁）人。秦末农民起义领袖，军事家。</p><ul><li>楚国名将项燕之孙</li><li>随叔父项梁起兵反秦</li><li>巨鹿之战破秦军主力</li><li>自称&quot;西楚霸王&quot;</li><li>与刘邦争天下，兵败乌江自刎</li></ul><hr><h2 id="主要功绩" tabindex="-1">主要功绩 <a class="header-anchor" href="#主要功绩" aria-label="Permalink to &quot;主要功绩&quot;">​</a></h2><table tabindex="0"><thead><tr><th>战役</th><th>时间</th><th>影响</th></tr></thead><tbody><tr><td>巨鹿之战</td><td>公元前207年</td><td>歼灭秦军主力，决定秦朝覆亡</td></tr><tr><td>彭城之战</td><td>公元前205年</td><td>三万破刘邦五十六万联军</td></tr><tr><td>垓下之战</td><td>公元前202年</td><td>被围，兵败自刎</td></tr></tbody></table><hr><h2 id="历史评价" tabindex="-1">历史评价 <a class="header-anchor" href="#历史评价" aria-label="Permalink to &quot;历史评价&quot;">​</a></h2><p><strong>太史公曰：</strong> &quot;羽非有尺寸，乘势起陇亩之中，三年，遂将五诸侯灭秦，分裂天下，而封王侯，政由羽出，号为&#39;霸王&#39;，位虽不终，近古以来未尝有也。&quot;</p><p>项羽以力拔山兮气盖世的英雄气概，在秦末乱世中崛起，虽最终败于刘邦，但其短暂而辉煌的一生，已成为中国历史上英雄主义的象征。</p><hr><p><strong>分类：</strong> 史部 <strong>体裁：</strong> 典籍 <strong>时代：</strong> 两汉 <strong>标签：</strong> 史记、项羽、英雄、楚汉争霸</p>',18)])])}const u=a(d,[["render",i]]);export{p as __pageData,u as default};
